// Filtra solo events 'purchase' y normaliza para ga4_purchases_daily.
// Agrega por (fecha, source, medium, campaign) sumando eventCount.

const PURCHASE_EVENT = 'purchase';

const toIsoDate = (raw) => {
  const s = String(raw ?? '');
  if (/^\d{8}$/.test(s)) return `${s.slice(0,4)}-${s.slice(4,6)}-${s.slice(6,8)}`;
  if (/^\d{4}-\d{2}-\d{2}$/.test(s)) return s;
  return null;
};

const normalizeUtm = (raw) => {
  if (raw === null || raw === undefined) return null;
  const s = String(raw).trim().toLowerCase();
  if (!s || s === '(not set)' || s === '(none)') return null;
  return s
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .replace(/\s+/g, '-')
    .replace(/[^a-z0-9\-_().]/g, '');
};

const toInt = (v) => {
  const n = Number(v ?? 0);
  return Number.isFinite(n) ? Math.round(n) : 0;
};

const keyOf = (r) => `${r.fecha}|${r.utm_source ?? ''}|${r.utm_medium ?? ''}|${r.utm_campaign ?? ''}`;

const agg = new Map();
for (const item of $input.all()) {
  const r = item.json;
  if (String(r.eventName ?? '').toLowerCase() !== PURCHASE_EVENT) continue;
  const fecha = toIsoDate(r.date);
  if (!fecha) continue;
  const row = {
    fecha,
    utm_source: normalizeUtm(r.sessionSource),
    utm_medium: normalizeUtm(r.sessionMedium),
    utm_campaign: normalizeUtm(r.sessionCampaignName),
    purchases: toInt(r.eventCount),
  };
  const k = keyOf(row);
  const prev = agg.get(k);
  if (prev) prev.purchases += row.purchases;
  else agg.set(k, row);
}
return [...agg.values()].map(j => ({ json: j }));
